#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q, R, p1, p2;
        scanf("%d %d %d %d %d", &N, &Q, &R, &p1, &p2);
        long long A[N];
        for (int i = 0; i < N; i++) A[i] = 0;
        while (Q--) {
            int type;
            scanf("%d", &type);
            if (type == 0) {
                long long S, D, X, Y;
                scanf("%lld %lld %lld %lld", &S, &D, &X, &Y);
                for (int i = X - 1; i < Y; i++) {
                    A[i] += S;
                    S = (S + D) * R;
                }
            } else if (type == 1) {
                int X, g;
                scanf("%d %d", &X, &g);
                A[X - 1] = (A[X - 1] * g) % p2;
            } else {
                int X, Y;
                scanf("%d %d", &X, &Y);
                long long sum = 0;
                for (int i = X - 1; i < Y; i++) sum += A[i];
                printf("%lld\n", sum % p1);
            }
        }
    }
    return 0;
}

