import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            long R = sc.nextLong();
            long p1 = sc.nextLong();
            long p2 = sc.nextLong();
            long[] A = new long[N];
            while (Q-- > 0) {
                int type = sc.nextInt();
                if (type == 0) {
                    long S = sc.nextLong();
                    long D = sc.nextLong();
                    int X = sc.nextInt();
                    int Y = sc.nextInt();
                    for (int i = X - 1; i < Y; i++) {
                        A[i] += S;
                        S = (S + D) * R;
                    }
                } else if (type == 1) {
                    int X = sc.nextInt();
                    int g = sc.nextInt();
                    A[X - 1] = (A[X - 1] * g) % p2;
                } else {
                    int X = sc.nextInt();
                    int Y = sc.nextInt();
                    long sum = 0;
                    for (int i = X - 1; i < Y; i++) sum += A[i];
                    System.out.println(sum % p1);
                }
            }
        }
    }
}

